#!/usr/bin/env node
// Generated by OrchestKit Claude Plugin
// Created: 2026-04-19
//
// MDX compile regression check. Walks docs/site/content/docs/**/*.mdx and
// compiles every file with @mdx-js/mdx + remark-gfm. Exits 1 if any file
// fails to parse, with the exact filename + line:col + reason.
//
// Catches the class of bugs surfaced by #1399: nested same-length code
// fences in skill SKILL.md sources produce mdx where prose looks like JSX
// expressions, and acorn chokes deep inside `next build --webpack`.
//
// Usage (run from docs/site/ — its node_modules has @mdx-js/mdx via fumadocs-mdx):
//   cd docs/site && node scripts/test-mdx-compile.mjs                  # check all
//   cd docs/site && node scripts/test-mdx-compile.mjs path/to/one.mdx  # check one
//
// The repo wrapper at tests/unit/test-mdx-compile.sh handles the cd for you.
//
// Exit codes: 0 = all pass, 1 = at least one parse error.

import { readFile, readdir } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { join, relative, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
// This script lives in docs/site/scripts/ — the docs site root is one level up,
// the project root is three levels up.
const DOCS_SITE_ROOT = join(__dirname, '..');
const PROJECT_ROOT = join(__dirname, '..', '..', '..');
const DEFAULT_ROOT = join(DOCS_SITE_ROOT, 'content/docs');

// ANSI colors — only when stdout is a TTY
const useColor = process.stdout.isTTY;
const c = (code, s) => (useColor ? `\x1b[${code}m${s}\x1b[0m` : s);
const red = (s) => c(31, s);
const green = (s) => c(32, s);
const dim = (s) => c(2, s);
const bold = (s) => c(1, s);

async function walkMdx(dir) {
  const out = [];
  const entries = await readdir(dir, { withFileTypes: true });
  for (const entry of entries) {
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      // Skip node_modules and any hidden dirs
      if (entry.name === 'node_modules' || entry.name.startsWith('.')) continue;
      out.push(...(await walkMdx(full)));
    } else if (entry.isFile() && entry.name.endsWith('.mdx')) {
      out.push(full);
    }
  }
  return out;
}

async function compileOne(compile, remarkGfm, filePath) {
  const src = await readFile(filePath, 'utf8');
  try {
    await compile(src, { remarkPlugins: [remarkGfm] });
    return { ok: true };
  } catch (e) {
    return {
      ok: false,
      message: e.message ?? String(e),
      place: e.line ? `line ${e.line}:${e.column}` : (e.place ?? '(no location)'),
      reason: e.reason ?? null,
    };
  }
}

async function main() {
  // Resolve targets: arg = single file, otherwise walk default tree
  const arg = process.argv[2];
  let targets;
  if (arg) {
    if (!existsSync(arg)) {
      console.error(red(`✗ Path does not exist: ${arg}`));
      process.exit(2);
    }
    targets = [arg];
  } else {
    if (!existsSync(DEFAULT_ROOT)) {
      console.error(red(`✗ Default root not found: ${DEFAULT_ROOT}`));
      process.exit(2);
    }
    targets = await walkMdx(DEFAULT_ROOT);
  }

  if (targets.length === 0) {
    console.log(dim('No .mdx files found.'));
    process.exit(0);
  }

  // Lazy-load @mdx-js/mdx + remark-gfm; surface a useful error if missing
  let compile, remarkGfm;
  try {
    ({ compile } = await import('@mdx-js/mdx'));
    remarkGfm = (await import('remark-gfm')).default;
  } catch (e) {
    console.error(red('✗ Missing dev dependency.'));
    console.error(dim('  Install with: npm install --save-dev @mdx-js/mdx remark-gfm'));
    console.error(dim(`  Underlying error: ${e.message}`));
    process.exit(2);
  }

  const failures = [];
  let okCount = 0;
  for (const file of targets) {
    const rel = relative(PROJECT_ROOT, file);
    const result = await compileOne(compile, remarkGfm, file);
    if (result.ok) {
      okCount++;
    } else {
      failures.push({ file: rel, ...result });
    }
  }

  if (failures.length === 0) {
    console.log(green(`✓ ${okCount} mdx file${okCount === 1 ? '' : 's'} compiled cleanly.`));
    process.exit(0);
  }

  console.log(red(bold(`✗ ${failures.length} of ${targets.length} mdx file${targets.length === 1 ? '' : 's'} failed to compile:`)));
  console.log('');
  for (const f of failures) {
    console.log(red(`  ${bold(f.file)}`));
    console.log(`    ${dim('at')} ${f.place}`);
    console.log(`    ${dim('reason:')} ${f.reason ?? f.message}`);
    if (f.message && f.message !== f.reason) {
      console.log(`    ${dim('message:')} ${f.message}`);
    }
    console.log('');
  }
  console.log(dim('Common cause: nested code fences in skill SKILL.md sources.'));
  console.log(dim('See src/skills/CONTRIBUTING-SKILLS.md → "Nesting code fences".'));
  process.exit(1);
}

main().catch((e) => {
  console.error(red('✗ Unexpected error in mdx-compile check:'));
  console.error(e);
  process.exit(2);
});
